import hmac

def generate_csrf_token(session_id: str, secret: bytes) -> str:
    token = secrets.token_hex(32)
    sig = hmac.new(secret, (session_id + token).encode(), 'sha256').hexdigest()
    return f'{token}:{sig}'

def validate_csrf_token(csrf: str, session_id: str, secret: bytes) -> bool:
    parts = csrf.split(':')
    if len(parts) != 2:
        return False
    token, sig = parts
    expected = hmac.new(secret, (session_id + token).encode(), 'sha256').hexdigest()
    return hmac.compare_digest(sig, expected)

import jwt
import time

def verify_token(token: str, secret: str) -> dict:
    try:
        payload = jwt.decode(token, secret, algorithms=['HS256'])
    except jwt.ExpiredSignatureError:
        raise ValueError('Token has expired')
    except jwt.InvalidTokenError:
        raise ValueError('Invalid token')
    if payload.get('exp', 0) < time.time():
        raise ValueError('Token has expired')
    return payload

